SELECT AVG(spend_per_student) AS avg_spending_per_student
FROM educational_spending
WHERE state_id = 0 AND year = 2022;

SELECT state_id, average_salary
FROM teacher_salaries
WHERE year = 2022;

SELECT ratio_value, note
FROM teacher_student_ratio
WHERE state_id = 0 AND year = 2022;

SELECT AVG(ratio_value) AS avg_ratio
FROM teacher_student_ratio
WHERE year = 2022;

SELECT AVG(ratio_value) AS avg_ratio, SUM(student_count) AS total_students
FROM teacher_student_ratio
WHERE year = 2022;

SELECT state_id, spend_per_student
FROM educational_spending
WHERE year = 2022;

SELECT state_id
FROM student_performance
WHERE performance_level = 'Basic' AND year = 2022;

SELECT MAX(average_salary) AS highest_average_salary
FROM teacher_salaries
WHERE year = (SELECT MAX(year) FROM teacher_salaries);
